// types/memorial.ts

export interface BasicInfo {
    fullName: string;
    birthDate: string;
    deathDate: string | null;
    isStillLiving: boolean;
    birthPlace: string;
    deathPlace: string;
    profilePhoto: File | null;
    profilePhotoPreview: string | null;
    epitaph: string;
}

export interface ChildhoodInfo {
    childhoodHome: string;
    familyBackground: string;
    schools: {
        elementary: string;
        highSchool: string;
        college: string;
        additionalEducation: string;
    };
    childhoodPersonality: string[];
    earlyInterests: string[];
    childhoodPhotos: Array<{
        file: File;
        preview: string;
        caption: string;
        year: string;
    }>;
}

export interface CareerEducation {
    occupations: Array<{
        id: string;
        title: string;
        company: string;
        yearsFrom: string;
        yearsTo: string;
        description: string;
    }>;
    careerHighlights: string[];
    education: {
        major: string;
        graduationYear: string;
        honors: string;
    };
}

export interface RelationshipsFamily {
    partners: Array<{
        id: string;
        name: string;
        relationshipType: string;
        yearsFrom: string;
        yearsTo: string;
        description: string;
        photo: File | null;
        photoPreview: string | null;
    }>;
    children: Array<{
        id: string;
        name: string;
        birthYear: string;
        description: string;
    }>;
    majorLifeEvents: Array<{
        id: string;
        year: string;
        title: string;
        category: 'marriage' | 'birth' | 'career' | 'achievement' | 'loss' | 'milestone';
        description: string;
    }>;
}

export interface PersonalityValues {
    personalityTraits: string[];
    coreValues: string[];
    passions: string[];
    lifePhilosophy: string;
    favoriteQuotes: Array<{
        id: string;
        text: string;
        context: string;
    }>;
    memorableSayings: string[];
}

export interface LifeStory {
    biography: string;
    lifeChapters: Array<{
        id: string;
        period: string;
        ageRange: string;
        title: string;
        description: string;
        keyEvents: string[];
    }>;
}

export interface MemoriesStories {
    sharedMemories: Array<{
        id: string;
        title: string;
        date: string;
        content: string;
        author: string;
        relationship: string;
    }>;
    impactStories: Array<{
        id: string;
        title: string;
        content: string;
        author: string;
    }>;
    invitedEmails: string[];
}

export interface MediaLegacy {
    coverPhoto: File | null;
    coverPhotoPreview: string | null;
    gallery: Array<{
        id: string;
        file: File;
        preview: string;
        caption: string;
        year: string;
        type: 'photo' | 'video';
    }>;
    videos: Array<{
        id: string;
        url: string;
        type: 'upload' | 'youtube' | 'vimeo';
    }>;
    voiceRecordings: Array<{
        id: string;
        file: File;
        title: string;
    }>;
    legacyStatement: string;
}

export interface MemorialData {
    step1: BasicInfo;
    step2: ChildhoodInfo;
    step3: CareerEducation;
    step4: RelationshipsFamily;
    step5: PersonalityValues;
    step6: LifeStory;
    step7: MemoriesStories;
    step8: MediaLegacy;
    currentStep: number;
    lastSaved: string | null;
}

export const TOTAL_STEPS = 9;

export const STEP_NAMES = [
    'Basic Information',
    'Early Life & Childhood',
    'Career & Education',
    'Relationships & Family',
    'Personality, Values & Passions',
    'Full Life Story',
    'Memories & Stories',
    'Photos, Videos & Legacy',
    'Review & Publish'
];